def find_big_movers(old_prices, new_prices, threshold=0.05):
    movers = {}
    for symbol in new_prices:
        old = old_prices.get(symbol)
        if old is None or old == 0:
            continue
        pct_change = (new_prices[symbol] - old) / old
        movers[symbol] = pct_change
    return {k: v for k, v in movers.items() if abs(v) >= threshold}

