from html.parser import HTMLParser

class PriceTableParser(HTMLParser):
    """Simple parser to extract symbol and price from a table."""
    def __init__(self):
        super().__init__()
        self.in_td = False
        self.cells = []
        self.prices = {}

    def handle_starttag(self, tag, attrs):
        if tag == 'td':
            self.in_td = True

    def handle_endtag(self, tag):
        if tag == 'td':
            self.in_td = False

    def handle_data(self, data):
        if self.in_td and data.strip():
            self.cells.append(data.strip())
            if len(self.cells) == 2:
                symbol, price = self.cells
                try:
                    self.prices[symbol] = float(price.replace(',', ''))
                except ValueError:
                    pass
                self.cells = []

