import json, time

class PriceNotFoundError(Exception):
    pass

def fetch_price(symbol, retries=3):
    import requests
    url = f'https://api.example.com/price/{symbol}'
    for attempt in range(retries):
        try:
            response = requests.get(url, timeout=10)
            response.raise_for_status()
            data = json.loads(response.text)
            return data['price']
        except requests.exceptions.Timeout:
            if attempt < retries - 1:
                time.sleep(2)
                continue
            print(f'Timeout after {retries} attempts')
            return None
        except json.JSONDecodeError:
            print(f'Malformed JSON response for {symbol}')
            return None
        except requests.exceptions.HTTPError as e:
            if response.status_code == 404:
                raise PriceNotFoundError(f'Price not found for {symbol}')
            raise

