import csv
from datetime import datetime

def load_prices(filepath):
    """Load price data with error handling for missing/corrupt data."""
    prices = []
    try:
        with open(filepath, 'r') as f:
            reader = csv.DictReader(f)
            rows = list(reader)
            if not rows:
                print(f'Warning: {filepath} is empty')
                return []

            for i, row in enumerate(rows, 1):
                try:
                    # Check for NaN close
                    if not row.get('close') or row['close'].strip() == '':
                        print(f'Row {i}: missing close value, skipping')
                        continue

                    # Validate date
                    try:
                        datetime.strptime(row['date'], '%Y-%m-%d')
                    except ValueError:
                        print(f'Row {i}: malformed date "{row["date"]}", skipping')
                        continue

                    prices.append({
                        'date': row['date'],
                        'close': float(row['close'])
                    })
                except (ValueError, KeyError) as e:
                    print(f'Row {i}: error processing row: {e}, skipping')
                    continue

    except FileNotFoundError:
        print(f'Error: {filepath} not found')
        return []

    return prices

