class Trade:
    def __init__(self, symbol, quantity, entry_price):
        self.symbol = symbol
        self.quantity = quantity
        self.entry_price = entry_price

    def pnl_pct(self, current_price):
        return ((current_price - self.entry_price) / self.entry_price) * 100

    def __str__(self):
        return f'{self.symbol}: {self.quantity} units @ ${self.entry_price:.2f}'

class SpotTrade(Trade):
    def __init__(self, symbol, quantity, entry_price, current_price):
        super().__init__(symbol, quantity, entry_price)
        self.current_price = current_price

    def value(self):
        return self.quantity * self.current_price

    def pnl(self):
        return (self.current_price - self.entry_price) * self.quantity

class MarginTrade(Trade):
    def __init__(self, symbol, quantity, entry_price, leverage):
        super().__init__(symbol, quantity, entry_price)
        self.leverage = leverage
        self.liquidation_price = entry_price * (1 - 0.85 / leverage)

    def pnl(self, current_price):
        change_pct = (current_price - self.entry_price) / self.entry_price
        return change_pct * self.leverage * 100  # PnL as % of margin

    def is_liquidated(self, current_price):
        return current_price <= self.liquidation_price

