import requests, json, time, hmac, hashlib

API_KEY = os.environ.get('EXCHANGE_API_KEY', 'demo_key')
SECRET = os.environ.get('EXCHANGE_SECRET', 'demo_secret')
BASE_URL = 'https://api.simulated-exchange.com/v1'

def create_signature(payload: dict, secret: str) -> str:
    """Create HMAC-SHA256 signature for request authentication."""
    message = json.dumps(payload, separators=(',', ':'))
    return hmac.new(secret.encode(), message.encode(), hashlib.sha256).hexdigest()

def place_limit_order(symbol: str, side: str, qty: float, price: float):
    payload = {
        'symbol': symbol,
        'side': side.lower(),
        'type': 'limit',
        'quantity': qty,
        'price': price,
        'timestamp': int(time.time() * 1000)
    }
    signature = create_signature(payload, SECRET)
    headers = {
        'X-API-Key': API_KEY,
        'X-Signature': signature,
        'Content-Type': 'application/json'
    }
    try:
        resp = requests.post(f'{BASE_URL}/orders', json=payload, headers=headers, timeout=10)
        if resp.status_code == 201:
            order = resp.json()
            print(f'Order placed: {order["id"]} | {side.upper()} {qty} {symbol} @ ${price:.2f}')
            return order
        elif resp.status_code == 401:
            print('Authentication failed. Check API key and signature.')
        elif resp.status_code == 400:
            errors = resp.json().get('errors', [])
            print(f'Bad request: {errors}')
        elif resp.status_code == 429:
            print('Rate limited. Retrying after delay...')
            time.sleep(5)
            return place_limit_order(symbol, side, qty, price)
        else:
            print(f'Unexpected error: {resp.status_code} - {resp.text}')
    except requests.Timeout:
        print('Request timed out. Exchange may be slow.')
    except requests.ConnectionError:
        print('Could not reach exchange. Check your network.')
    return None

