class OrderBook:
    def __init__(self, symbol):
        self.bids = []
        self.asks = []

    def add_order(self, price, qty, side):
        if side == 'buy':
            self.bids.append((price, qty))
            self.bids.sort(key=lambda x: -x[0])
        else:
            self.asks.append((price, qty))
            self.asks.sort(key=lambda x: x[0])
        self._match()

    def best_bid(self): return self.bids[0][0] if self.bids else None
    def best_ask(self): return self.asks[0][0] if self.asks else None

    def _match(self):
        while self.bids and self.asks and self.bids[0][0] >= self.asks[0][0]:
            print(f'Filled at {self.asks[0][0]}')
            self.bids.pop(0)
            self.asks.pop(0)

