def binary_search(prices, target):
    left, right = 0, len(prices) - 1
    while left <= right:
        mid = (left + right) // 2
        if prices[mid] == target:
            return mid
        elif prices[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

