class UndoRedo:
    def __init__(self):
        self.undo_stack = []
        self.redo_stack = []

    def execute(self, action):
        self.undo_stack.append(action)
        self.redo_stack.clear()

    def undo(self):
        if self.undo_stack:
            self.redo_stack.append(self.undo_stack.pop())

