import pytest

def calc_position_size(balance, risk_pct, entry, stop):
    if risk_pct <= 0:
        raise ValueError('risk_pct must be positive')
    risk_amount = balance * risk_pct
    risk_per_unit = abs(entry - stop)
    if risk_per_unit == 0:
        raise ZeroDivisionError('entry and stop cannot be equal')
    return risk_amount / risk_per_unit

